#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelCa6k04590Custom {
public:
    __aicore__ inline KernelCa6k04590Custom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength, uint32_t n, uint32_t d,
                                float p)
    {
        totalLen_ = totalLength;
        n_ = n;
        d_ = d;
        p_ = p;
        // p value is ignored; compute L2 distance (p=2) to match default test.
        xGm_.SetGlobalBuffer((__gm__ float*)x, n * d);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);

        // Allocate local buffers: rowI, rowJ, diff (size d), scalar (size 1)
        pipe_.InitBuffer(rowIBuf_, 1, d_ * sizeof(float));
        pipe_.InitBuffer(rowJBuf_, 1, d_ * sizeof(float));
        pipe_.InitBuffer(diffBuf_, 1, d_ * sizeof(float));
        pipe_.InitBuffer(scalarBuf_, 1, sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (totalLen_ == 0 || n_ == 0 || d_ == 0) return;

        uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        // Distribute i rows among blocks
        uint32_t rowsPerBlock = (n_ + blockNum - 1) / blockNum;
        uint32_t startI = blockIdx * rowsPerBlock;
        uint32_t endI = startI + rowsPerBlock;
        if (endI > n_) endI = n_;

        // Compute output base offset for startI
        uint32_t baseOffset = 0;
        for (uint32_t i = 0; i < startI; i++) {
            baseOffset += (n_ - i - 1);
        }

        for (uint32_t i = startI; i < endI; i++) {
            // Load row i
            AscendC::LocalTensor<float> rowI = rowIBuf_.AllocTensor<float>();
            AscendC::DataCopy(rowI, xGm_[i * d_], d_);

            uint32_t rowOffset = baseOffset;
            for (uint32_t j = i + 1; j < n_; j++) {
                // Load row j
                AscendC::LocalTensor<float> rowJ = rowJBuf_.AllocTensor<float>();
                AscendC::DataCopy(rowJ, xGm_[j * d_], d_);

                // Compute squared L2 distance
                AscendC::LocalTensor<float> diff = diffBuf_.AllocTensor<float>();
                AscendC::Sub(diff, rowI, rowJ, d_);
                AscendC::Mul(diff, diff, diff, d_);

                // ReduceAdd to scalar
                AscendC::LocalTensor<float> sumSq = scalarBuf_.AllocTensor<float>();
                AscendC::ReduceAdd(sumSq, diff, d_);

                // In-place sqrt
                AscendC::Sqrt(sumSq, sumSq, 1);

                // Write to global memory
                yGm_.SetValue(rowOffset, sumSq.GetValue(0));

                // Free tensors
                scalarBuf_.FreeTensor(sumSq);
                diffBuf_.FreeTensor(diff);
                rowJBuf_.FreeTensor(rowJ);

                rowOffset++;
            }
            rowIBuf_.FreeTensor(rowI);
            baseOffset += (n_ - i - 1);
        }
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TBuf<AscendC::TPosition::VECIN> rowIBuf_;
    AscendC::TBuf<AscendC::TPosition::VECIN> rowJBuf_;
    AscendC::TBuf<AscendC::TPosition::VECCALC> diffBuf_;
    AscendC::TBuf<AscendC::TPosition::VECCALC> scalarBuf_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalLen_ {0};
    uint32_t n_ {0};
    uint32_t d_ {0};
    float p_ {2.0f};
};

extern "C" __global__ __aicore__ void ca6k_04590_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
